    StringBuilder buf = new StringBuilder(96);
    buf.append(SummarizerUtils.datePeriod(cdsProduct.getPaymentSchedule().getStartDate(),
        cdsProduct.getPaymentSchedule().getEndDate()));
    buf.append(' ');
    buf.append(cdsProduct.getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(cdsProduct.getCurrency(), cdsProduct.getNotional()));
    buf.append(" TRANCHE ");
    buf.append(SummarizerUtils.percent(cdsProduct.getAttachmentPoint()));
    buf.append("-");
    buf.append(SummarizerUtils.percent(cdsProduct.getDetachmentPoint()));
    buf.append(" / ");
    buf.append(SummarizerUtils.percent(cdsProduct.getFixedRate()));
    buf.append(" : ");
    buf.append(SummarizerUtils.dateRange(cdsProduct.getPaymentSchedule().getStartDate(),
        cdsProduct.getPaymentSchedule().getEndDate()));
