  }

  // calculates market quote bucketed IR01 for one scenario
  CurrencyParameterSensitivities ir01MarketQuoteBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return tradePricer.parSpread01MarketQuoteBucketed(trade, ratesProvider, ONE_BASIS_POINT, refData);
  }

  //-------------------------------------------------------------------------
  // calculates PV01 calibrated sum for all scenarios
  CurrencyScenarioArray pv01CalibratedSum(
      ResolvedCdsTrancheTrade trade,
