    PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);
    CurrencyParameterSensitivities paramSensitivity = MARKET_QUOTE_SENS.sensitivity(pointSensitivity, ratesProvider);
    return paramSensitivity.total();
  }

  //-------------------------------------------------------------------------
  // calculates PV01 market quote bucketed for all scenarios
  ScenarioArray<CurrencyParameterSensitivities> pv01MarketQuoteBucketed(
