  //-------------------------------------------------------------------------
  // calculates CS01 bucketed for all scenarios
  ScenarioArray<CurrencyParameterSensitivities> cs01Bucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
