  }

  // calculates CS01 bucketed for one scenario
  CurrencyParameterSensitivities cs01Bucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return tradePricer.parSpread01CalibratedBucketed(trade, ratesProvider, ONE_BASIS_POINT, refData);
  }

  //-------------------------------------------------------------------------
  // calculates recovery01 for all scenarios
  CurrencyScenarioArray recovery01(
      ResolvedCdsTrancheTrade trade,
