    return CurrencyScenarioArray.of(
        marketData.getScenarioCount(),
        i -> expectedLoss(trade, marketData.scenario(i).creditRatesProvider(), refData));
  }

  // calculates expected loss for one scenario
  CurrencyAmount expectedLoss(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return tradePricer.expectedLoss(trade, ratesProvider, refData);
  }

}

