import com.opengamma.strata.product.Product;
import com.opengamma.strata.product.common.BuySell;

/**
 * A CDS tranche product.
 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index, defined by
 * attachment and detachment points that determine the subordination level.
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * The underlying CDS index.
   * <p>
   * The tranche is defined over this CDS index.
   */
  @PropertyDefinition(validate = "notNull")
  private final CdsIndex underlyingIndex;
  /**
   * The attachment point as a fraction (0.0 to 1.0).
   * <p>
   * The attachment point determines the lower boundary of the tranche.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double attachmentPoint;
  /**
   * The detachment point as a fraction (0.0 to 1.0).
   * <p>
   * The detachment point determines the upper boundary of the tranche.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double detachmentPoint;
  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection.
   * A value of 'Sell' implies selling protection.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The currency of the CDS tranche.
   * <p>
   * The amounts of the notional are expressed in terms of this currency.
   */
  @PropertyDefinition(validate = "notNull")
  private final Currency currency;
  /**
   * The notional amount, must be non-negative.
   * <p>
   * The fixed notional amount applicable during the lifetime of the CDS tranche.
   * The currency of the notional is specified by {@code currency}.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
  private final double notional;
  /**
   * The payment schedule.
   * <p>
   * This is used to define the payment periods.
   */
  @PropertyDefinition(validate = "notNull")
  private final PeriodicSchedule paymentSchedule;
  /**
   * The fixed coupon rate.
   * <p>
   * This must be represented in decimal form.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double fixedRate;
  /**
   * The day count convention.
   * <p>
   * This is used to convert dates to a numerical value.
   * <p>
   * When building, this will default to 'Act/360'.
   */
  @PropertyDefinition(validate = "notNull")
  private final DayCount dayCount;
  /**
   * The payment on default.
   * <p>
   * Whether the accrued premium is paid in the event of a default.
   * <p>
   * When building, this will default to 'AccruedPremium'.
   */
  @PropertyDefinition(validate = "notNull")
  private final PaymentOnDefault paymentOnDefault;
  /**
   * The protection start of the day.
   * <p>
   * When the protection starts on the start date.
   * <p>
   * When building, this will default to 'Beginning'.
   */
  @PropertyDefinition(validate = "notNull")
  private final ProtectionStartOfDay protectionStart;
  /**
   * The number of days between valuation date and step-in date.
   * <p>
   * The step-in date is also called protection effective date.
   * It is usually 1 calendar day for standardized CDS tranche contracts.
   * <p>
   * When building, this will default to 1 calendar day.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment stepinDateOffset;
  /**
   * The number of days between valuation date and settlement date.
   * <p>
   * It is usually 3 business days for standardized CDS tranche contracts.
   * <p>
   * When building, this will default to 3 business days in the calendar of the payment schedule.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment settlementDateOffset;

  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
    builder.dayCount = DayCounts.ACT_360;
    builder.paymentOnDefault = PaymentOnDefault.ACCRUED_PREMIUM;
    builder.protectionStart = ProtectionStartOfDay.BEGINNING;
    builder.stepinDateOffset = DaysAdjustment.ofCalendarDays(1);
  }

  //-------------------------------------------------------------------------
  @Override
  public ImmutableSet<Currency> allCurrencies() {
    return ImmutableSet.of(currency);
  }

  //-------------------------------------------------------------------------
  @Override
  public ResolvedCdsTranche resolve(ReferenceData refData) {
    ResolvedCdsIndex resolvedIndex = underlyingIndex.resolve(refData);
    return ResolvedCdsTranche.builder()
        .underlyingIndex(resolvedIndex)
        .attachmentPoint(attachmentPoint)
        .detachmentPoint(detachmentPoint)
        .buySell(buySell)
        .currency(currency)
        .notional(notional)
        .paymentPeriods(resolvedIndex.getPaymentPeriods())
        .protectionEndDate(resolvedIndex.getProtectionEndDate())
        .dayCount(dayCount)
        .paymentOnDefault(paymentOnDefault)
        .protectionStart(protectionStart)
        .stepinDateOffset(stepinDateOffset)
        .settlementDateOffset(settlementDateOffset)
        .build();
  }

  //------------------------- AUTOGENERATED START -------------------------
  /**
   * The meta-bean for {@code CdsTranche}.
   * @return the meta-bean, not null
   */
  public static CdsTranche.Meta meta() {
    return CdsTranche.Meta.INSTANCE;
  }

  static {
    MetaBean.register(CdsTranche.Meta.INSTANCE);
  }

  /**
   * The serialization version id.
   */
  private static final long serialVersionUID = 1L;

  /**
   * Returns a builder used to create an instance of the bean.
   * @return the builder, not null
   */
  public static CdsTranche.Builder builder() {
    return new CdsTranche.Builder();
  }

  private CdsTranche(
      CdsIndex underlyingIndex,
      double attachmentPoint,
      double detachmentPoint,
      BuySell buySell,
      Currency currency,
      double notional,
      PeriodicSchedule paymentSchedule,
      double fixedRate,
      DayCount dayCount,
      PaymentOnDefault paymentOnDefault,
      ProtectionStartOfDay protectionStart,
      DaysAdjustment stepinDateOffset,
      DaysAdjustment settlementDateOffset) {
    JodaBeanUtils.notNull(underlyingIndex, "underlyingIndex");
    ArgChecker.notNegative(attachmentPoint, "attachmentPoint");
    ArgChecker.notNegative(detachmentPoint, "detachmentPoint");
    JodaBeanUtils.notNull(buySell, "buySell");
    JodaBeanUtils.notNull(currency, "currency");
    ArgChecker.notNegativeOrZero(notional, "notional");
    JodaBeanUtils.notNull(paymentSchedule, "paymentSchedule");
    ArgChecker.notNegative(fixedRate, "fixedRate");
    JodaBeanUtils.notNull(dayCount, "dayCount");
    JodaBeanUtils.notNull(paymentOnDefault, "paymentOnDefault");
    JodaBeanUtils.notNull(protectionStart, "protectionStart");
    JodaBeanUtils.notNull(stepinDateOffset, "stepinDateOffset");
    JodaBeanUtils.notNull(settlementDateOffset, "settlementDateOffset");
    this.underlyingIndex = underlyingIndex;
    this.attachmentPoint = attachmentPoint;
    this.detachmentPoint = detachmentPoint;
    this.buySell = buySell;
    this.currency = currency;
    this.notional = notional;
    this.paymentSchedule = paymentSchedule;
    this.fixedRate = fixedRate;
    this.dayCount = dayCount;
    this.paymentOnDefault = paymentOnDefault;
    this.protectionStart = protectionStart;
    this.stepinDateOffset = stepinDateOffset;
    this.settlementDateOffset = settlementDateOffset;
  }

  @Override
  public CdsTranche.Meta metaBean() {
    return CdsTranche.Meta.INSTANCE;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the underlying CDS index.
   * <p>
   * The tranche is defined over this CDS index.
   * @return the value of the property, not null
   */
  public CdsIndex getUnderlyingIndex() {
    return underlyingIndex;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the attachment point as a fraction (0.0 to 1.0).
   * <p>
   * The attachment point determines the lower boundary of the tranche.
   * @return the value of the property
   */
  public double getAttachmentPoint() {
    return attachmentPoint;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the detachment point as a fraction (0.0 to 1.0).
   * <p>
   * The detachment point determines the upper boundary of the tranche.
   * @return the value of the property
   */
  public double getDetachmentPoint() {
    return detachmentPoint;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection.
   * A value of 'Sell' implies selling protection.
   * @return the value of the property, not null
   */
  public BuySell getBuySell() {
    return buySell;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the currency of the CDS tranche.
   * <p>
   * The amounts of the notional are expressed in terms of this currency.
   * @return the value of the property, not null
   */
  public Currency getCurrency() {
    return currency;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the notional amount, must be non-negative.
   * <p>
   * The fixed notional amount applicable during the lifetime of the CDS tranche.
   * The currency of the notional is specified by {@code currency}.
   * @return the value of the property
   */
  public double getNotional() {
    return notional;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the payment schedule.
   * <p>
   * This is used to define the payment periods.
   * @return the value of the property, not null
   */
  public PeriodicSchedule getPaymentSchedule() {
    return paymentSchedule;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the fixed coupon rate.
   * <p>
   * This must be represented in decimal form.
   * @return the value of the property
   */
  public double getFixedRate() {
    return fixedRate;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the day count convention.
   * <p>
   * This is used to convert dates to a numerical value.
   * <p>
   * When building, this will default to 'Act/360'.
   * @return the value of the property, not null
   */
  public DayCount getDayCount() {
    return dayCount;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the payment on default.
   * <p>
   * Whether the accrued premium is paid in the event of a default.
   * <p>
   * When building, this will default to 'AccruedPremium'.
   * @return the value of the property, not null
   */
  public PaymentOnDefault getPaymentOnDefault() {
    return paymentOnDefault;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the protection start of the day.
   * <p>
   * When the protection starts on the start date.
   * <p>
   * When building, this will default to 'Beginning'.
   * @return the value of the property, not null
   */
  public ProtectionStartOfDay getProtectionStart() {
    return protectionStart;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the number of days between valuation date and step-in date.
   * <p>
   * The step-in date is also called protection effective date.
   * It is usually 1 calendar day for standardized CDS tranche contracts.
   * <p>
   * When building, this will default to 1 calendar day.
   * @return the value of the property, not null
   */
  public DaysAdjustment getStepinDateOffset() {
    return stepinDateOffset;
  }

  //-----------------------------------------------------------------------
  /**
   * Gets the number of days between valuation date and settlement date.
   * <p>
   * It is usually 3 business days for standardized CDS tranche contracts.
   * <p>
   * When building, this will default to 3 business days in the calendar of the payment schedule.
   * @return the value of the property, not null
   */
  public DaysAdjustment getSettlementDateOffset() {
    return settlementDateOffset;
  }

  //-----------------------------------------------------------------------
  /**
   * Returns a builder that allows this bean to be mutated.
   * @return the mutable builder, not null
   */
  public Builder toBuilder() {
    return new Builder(this);
  }

  @Override
  public boolean equals(Object obj) {
    if (obj == this) {
      return true;
    }
    if (obj != null && obj.getClass() == this.getClass()) {
      CdsTranche other = (CdsTranche) obj;
      return JodaBeanUtils.equal(underlyingIndex, other.underlyingIndex) &&
          JodaBeanUtils.equal(attachmentPoint, other.attachmentPoint) &&
          JodaBeanUtils.equal(detachmentPoint, other.detachmentPoint) &&
          JodaBeanUtils.equal(buySell, other.buySell) &&
          JodaBeanUtils.equal(currency, other.currency) &&
          JodaBeanUtils.equal(notional, other.notional) &&
          JodaBeanUtils.equal(paymentSchedule, other.paymentSchedule) &&
          JodaBeanUtils.equal(fixedRate, other.fixedRate) &&
          JodaBeanUtils.equal(dayCount, other.dayCount) &&
          JodaBeanUtils.equal(paymentOnDefault, other.paymentOnDefault) &&
          JodaBeanUtils.equal(protectionStart, other.protectionStart) &&
          JodaBeanUtils.equal(stepinDateOffset, other.stepinDateOffset) &&
          JodaBeanUtils.equal(settlementDateOffset, other.settlementDateOffset);
    }
    return false;
  }

  @Override
  public int hashCode() {
    int hash = getClass().hashCode();
    hash = hash * 31 + JodaBeanUtils.hashCode(underlyingIndex);
    hash = hash * 31 + JodaBeanUtils.hashCode(attachmentPoint);
    hash = hash * 31 + JodaBeanUtils.hashCode(detachmentPoint);
    hash = hash * 31 + JodaBeanUtils.hashCode(buySell);
    hash = hash * 31 + JodaBeanUtils.hashCode(currency);
    hash = hash * 31 + JodaBeanUtils.hashCode(notional);
    hash = hash * 31 + JodaBeanUtils.hashCode(paymentSchedule);
    hash = hash * 31 + JodaBeanUtils.hashCode(fixedRate);
    hash = hash * 31 + JodaBeanUtils.hashCode(dayCount);
    hash = hash * 31 + JodaBeanUtils.hashCode(paymentOnDefault);
    hash = hash * 31 + JodaBeanUtils.hashCode(protectionStart);
    hash = hash * 31 + JodaBeanUtils.hashCode(stepinDateOffset);
    hash = hash * 31 + JodaBeanUtils.hashCode(settlementDateOffset);
    return hash;
  }

  @Override
  public String toString() {
    StringBuilder buf = new StringBuilder(512);
