import com.opengamma.strata.product.credit.ResolvedCds;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;

/**
 * Pricer for CDS tranche based on ISDA standard model.
 * <p>
 * The CDS tranche pricing uses the underlying CDS index pricer logic,
 * applying tranche-specific loss allocation based on attachment and detachment points.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT =
      new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for CDS index products.
   */
  private final IsdaHomogenousCdsIndexProductPricer indexPricer;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.indexPricer = new IsdaHomogenousCdsIndexProductPricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return indexPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the CDS tranche product.
   * <p>
   * The present value of the product is based on {@code referenceDate}.
   * This is typically the valuation date, or cash settlement date if the product is associated with a {@code Trade}.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    ArgChecker.notNull(tranche, "tranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");

    // Get the present value from the underlying index
    CurrencyAmount indexPv = indexPricer.presentValue(
        tranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        priceType,
        refData);

    // Apply tranche-specific loss allocation
    double attachmentPoint = tranche.getAttachmentPoint();
    double detachmentPoint = tranche.getDetachmentPoint();

    // The loss absorption factor scales the protection leg based on tranche position
    double lossAbsorptionFactor = detachmentPoint - attachmentPoint;

    // Scale the present value by the tranche size and position
    double scaledAmount = indexPv.getAmount() * lossAbsorptionFactor;

    return CurrencyAmount.of(tranche.getCurrency(), scaledAmount);
  }

  /**
   * Calculates the price of the CDS tranche product, which is the minus of the present value per unit notional.
   * <p>
   * This method can calculate the clean or dirty price, see {@link PriceType}.
   * If calculating the clean price, the accrued interest is calculated based on the step-in date.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    CurrencyAmount pv = presentValue(tranche, ratesProvider, referenceDate, priceType, refData);
    return -pv.getAmount() / tranche.getNotional();
  }

  /**
   * Calculates the price sensitivity of the product.
   * <p>
   * The price sensitivity of the product is the sensitivity of price to the underlying curves.
   *
   * @param tranche  the product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder priceSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.notNull(tranche, "tranche");
    ArgChecker.notNull(ratesProvider, "ratesProvider");
    ArgChecker.notNull(referenceDate, "referenceDate");

    // Get the price sensitivity from the underlying index
    PointSensitivityBuilder indexSensitivity = indexPricer.priceSensitivity(
        tranche.getUnderlyingIndex(),
        ratesProvider,
        referenceDate,
        refData);

    // Apply tranche-specific loss allocation scaling
    double attachmentPoint = tranche.getAttachmentPoint();
    double detachmentPoint = tranche.getDetachmentPoint();
    double lossAbsorptionFactor = detachmentPoint - attachmentPoint;

    // Scale the sensitivity by the loss absorption factor
    return indexSensitivity.multipliedBy(lossAbsorptionFactor);
  }
}

