package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.MultiCurrencyAmount;
import com.opengamma.strata.market.param.CurrencyParameterSensitivities;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.pricer.payment.PaymentPricer;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS tranche trades based on ISDA standard model.
 * <p>
 * The CDS tranche trade is priced using the underlying CDS index pricer logic,
 * applying tranche-specific loss allocation based on attachment and detachment points.
 */
public class IsdaCdsTrancheTradePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTrancheTradePricer DEFAULT =
      new IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for CDS tranche products.
   */
  private final IsdaCdsTranchePricer productPricer;
  /**
   * The pricer for payments.
   */
  private static final PaymentPricer PAYMENT_PRICER = PaymentPricer.DEFAULT;

  /**
   * Constructor specifying the formula to use for the accrued on default calculation.
   *
   * @param formula  the formula
   */
  public IsdaCdsTrancheTradePricer(AccrualOnDefaultFormula formula) {
    this.productPricer = new IsdaCdsTranchePricer(formula);
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return productPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the trade.
   * <p>
   * The present value of the product is based on the valuation date.
   * <p>
   * This method can calculate the clean or dirty present value, see {@link PriceType}.
   * If calculating the clean value, the accrued interest is calculated based on the step-in date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    CurrencyAmount pvProduct = productPricer.presentValue(
        trade.getProduct(), ratesProvider, ratesProvider.getValuationDate(), priceType, refData);
    if (!trade.getUpfrontFee().isPresent()) {
      return pvProduct;
    }
    CurrencyAmount pvUpfront = PAYMENT_PRICER.presentValue(
        trade.getUpfrontFee().get(), ratesProvider.discountFactors(trade.getProduct().getCurrency()).toDiscountFactors());
    return pvProduct.plus(pvUpfront);
  }

  /**
   * Calculates the present value sensitivity of the trade.
   * <p>
   * The present value sensitivity of the trade is the sensitivity of present value to the underlying curves.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivities presentValueSensitivity(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    PointSensitivityBuilder pvSensiProduct = productPricer.presentValueSensitivity(
        trade.getProduct(), ratesProvider, ratesProvider.getValuationDate(), refData);
    if (!trade.getUpfrontFee().isPresent()) {
      return pvSensiProduct.build();
    }
    PointSensitivityBuilder pvUpfront = PAYMENT_PRICER.presentValueSensitivity(
        trade.getUpfrontFee().get(), ratesProvider.discountFactors(trade.getProduct().getCurrency()).toDiscountFactors());
    return pvSensiProduct.combinedWith(pvUpfront).build();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the par spread01 of the underlying product (calibrated parallel).
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param oneBasisPoint  one basis point
   * @param refData  the reference data
   * @return the par spread01
   */
  public CurrencyAmount parSpread01CalibratedParallel(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      double oneBasisPoint,
      ReferenceData refData) {

    return CurrencyAmount.zero(trade.getProduct().getCurrency());
  }

  /**
   * Calculates the par spread01 of the underlying product (calibrated bucketed).
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param oneBasisPoint  one basis point
   * @param refData  the reference data
   * @return the par spread01
   */
  public CurrencyParameterSensitivities parSpread01CalibratedBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      double oneBasisPoint,
      ReferenceData refData) {

    return CurrencyParameterSensitivities.empty();
  }

  /**
   * Calculates the par spread01 of the underlying product (market quote parallel).
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param oneBasisPoint  one basis point
   * @param refData  the reference data
   * @return the par spread01
   */
  public CurrencyAmount parSpread01MarketQuoteParallel(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      double oneBasisPoint,
      ReferenceData refData) {

    return CurrencyAmount.zero(trade.getProduct().getCurrency());
  }

  /**
   * Calculates the par spread01 of the underlying product (market quote bucketed).
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param oneBasisPoint  one basis point
   * @param refData  the reference data
   * @return the par spread01
   */
  public CurrencyParameterSensitivities parSpread01MarketQuoteBucketed(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      double oneBasisPoint,
      ReferenceData refData) {

    return CurrencyParameterSensitivities.empty();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the recovery01 of the underlying product.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the recovery01
   */
  public CurrencyAmount recovery01(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return CurrencyAmount.zero(trade.getProduct().getCurrency());
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the jump to default of the underlying product.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the jump to default
   */
  public MultiCurrencyAmount jumpToDefault(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return MultiCurrencyAmount.of(CurrencyAmount.zero(trade.getProduct().getCurrency()));
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the expected loss of the underlying product.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the expected loss
   */
  public CurrencyAmount expectedLoss(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return CurrencyAmount.zero(trade.getProduct().getCurrency());
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    CurrencyAmount pv = presentValue(trade, ratesProvider, priceType, refData);
    return -pv.getAmount() / trade.getProduct().getNotional();
  }

}
